class Solution: def validateStackSequences(self, pushed: List[int], popped: List[int]) -> bool: s = []; for x in pushed: s.append(x); stack = []; p = 0; while p < len(popped): while s and s[-1] != popped[p]: stack.append(s.pop()); if s and s[-1] == popped[p]: s.pop(); else: return False; p++; return True;
