using namespace std;
class Solution {
public:
bool validateStackSequences(vector<int>& pushed, vector<int>& popped) {
stack<int> s;
for (int x : pushed) s.push(x);
int p = 0;
while (p < popped.size()) {
while (!s.empty() && s.top() != popped[p])
stack<int> temp;
while (!s.empty() && s.top() != popped[p])
{ temp.push(s.top()); s.pop(); }
if (s.top() == popped[p]) s.pop();
else return false;
p++;
}
return true;
}
};
